mapper.select:
SELECT dma.id, dma.user_id, dma.room_id, dma.apartment_id, dma.landlord_id, dma.name, dma.phone, dma.identification_number, dma.email, dma.emergency_contact, dma.emergency_phone, dma.lease_start_date, dma.lease_end_date, dma.lease_term_id, dma.rent, dma.deposit, dma.payment_type_id, dma.status, dma.processor_id, dma.processor_type, dma.rejection_reason, dma.processed_at, dma.additional_info, dma.create_time, dma.update_time, -- 关联信息 ri.room_number, ai.name as apartment_name, lt.name as lease_term_name, pt.name as payment_type_name, ui.nickname as landlord_name, ui.phone as landlord_phone, CASE WHEN dma.landlord_id IS NULL THEN 1 ELSE 2 END as publisher_type, CASE WHEN dma.landlord_id IS NULL THEN '官方房源' ELSE '房东房源' END as publisher_type_name, CASE WHEN dma.processor_type = 1 THEN su.name WHEN dma.processor_type = 2 THEN ui2.nickname ELSE NULL END as processor_name FROM direct_move_in_application dma LEFT JOIN room_info ri ON dma.room_id = ri.id LEFT JOIN apartment_info ai ON dma.apartment_id = ai.id LEFT JOIN lease_term lt ON dma.lease_term_id = lt.id LEFT JOIN payment_type pt ON dma.payment_type_id = pt.id LEFT JOIN user_info ui ON dma.landlord_id = ui.id LEFT JOIN system_user su ON dma.processor_id = su.id AND dma.processor_type = 1 LEFT JOIN user_info ui2 ON dma.processor_id = ui2.id AND dma.processor_type = 2 WHERE dma.status = 1 AND dma.is_deleted = 0
AND dma.processor_id = #{processorId}
AND dma.processor_type = #{processorType}
AND dma.landlord_id IS NULL
AND dma.landlord_id IS NOT NULL
ORDER BY dma.create_time DESC

SELECT dma.id, dma.user_id, dma.room_id, dma.apartment_id, dma.landlord_id, dma.name, dma.phone, dma.identification_number, dma.email, dma.emergency_contact, dma.emergency_phone, dma.lease_start_date, dma.lease_end_date, dma.lease_term_id, dma.rent, dma.deposit, dma.payment_type_id, dma.status, dma.processor_id, dma.processor_type, dma.rejection_reason, dma.processed_at, dma.additional_info, dma.create_time, dma.update_time, -- 关联信息 ri.room_number, ai.name as apartment_name, lt.name as lease_term_name, pt.name as payment_type_name, ui.nickname as landlord_name, ui.phone as landlord_phone, CASE WHEN dma.landlord_id IS NULL THEN 1 ELSE 2 END as publisher_type, CASE WHEN dma.landlord_id IS NULL THEN '官方房源' ELSE '房东房源' END as publisher_type_name, CASE WHEN dma.processor_type = 1 THEN su.name WHEN dma.processor_type = 2 THEN ui2.nickname ELSE NULL END as processor_name FROM direct_move_in_application dma LEFT JOIN room_info ri ON dma.room_id = ri.id LEFT JOIN apartment_info ai ON dma.apartment_id = ai.id LEFT JOIN lease_term lt ON dma.lease_term_id = lt.id LEFT JOIN payment_type pt ON dma.payment_type_id = pt.id LEFT JOIN user_info ui ON dma.landlord_id = ui.id LEFT JOIN system_user su ON dma.processor_id = su.id AND dma.processor_type = 1 LEFT JOIN user_info ui2 ON dma.processor_id = ui2.id AND dma.processor_type = 2 WHERE dma.is_deleted = 0
AND dma.user_id = #{userId}
AND dma.status = #{status}
AND dma.processor_id = #{processorId}
AND dma.processor_type = #{processorType}
AND dma.landlord_id IS NULL
AND dma.landlord_id IS NOT NULL
ORDER BY dma.create_time DESC

SELECT *
FROM direct_move_in_application
WHERE processor_id = #{processorId}
  AND processor_type = #{processorType}
  AND is_deleted = 0
ORDER BY create_time DESC
